        return Constraint.Skip
    lhs = sum(model.at[cr, cb, q] * model.w[cr, cb, cfr, i, t] for (cr, cb) in model.cfcb)
    rhs = 0
    if cfr in model.cfrerf:
        rhs += sum(value(model.quu[cfr, q]) * model.xf[cfr, i, j, t] for j in model.j)
    if cfr in model.cfrrf:
